import{_ as o,c as r,o as s,ae as n}from"./chunks/framework.Cqi9LMMK.js";const h=JSON.parse('{"title":"Менеджер настроек","description":"","frontmatter":{"title":"Менеджер настроек"},"headers":[],"relativePath":"ru/options/settings_management.md","filePath":"ru/options/settings_management.md"}'),e={name:"ru/options/settings_management.md"};function a(g,t,i,l,d,p){return s(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="сохранение-импорт-и-экспорт" tabindex="-1">Сохранение, импорт и экспорт <a class="header-anchor" href="#сохранение-импорт-и-экспорт" aria-label="Permalink to &quot;Сохранение, импорт и экспорт&quot;">​</a></h1><p>В разделе <strong>Options → General</strong> внизу доступны три действия: <strong>Import</strong>, <strong>Export</strong> и <strong>Reset</strong>. Они работают и в <strong>расширении</strong>, и в <strong>автономном (standalone)</strong> режиме, но <strong>физическое место записи</strong> и <strong>состав экспортируемого файла</strong> зависят от варианта запуска.</p><p>Повседневное изменение любых полей в Options <strong>автоматически сохраняется</strong> с небольшой задержкой (чтобы не писать на диск на каждый символ). Отдельной кнопки «Сохранить» для обычных правок нет.</p><p>Краткая сводка «куда что ложится» по режимам — на странице <a href="/docs/ru/guide/install.html#storage">Установка → Где хранятся настройки</a>.</p><hr><h2 id="куда-записываются-данные-при-обычном-сохранении" tabindex="-1">Куда записываются данные при обычном сохранении <a class="header-anchor" href="#куда-записываются-данные-при-обычном-сохранении" aria-label="Permalink to &quot;Куда записываются данные при обычном сохранении&quot;">​</a></h2><h3 id="расширение-chrome-edge" tabindex="-1">Расширение (Chrome / Edge) <a class="header-anchor" href="#расширение-chrome-edge" aria-label="Permalink to &quot;Расширение (Chrome / Edge)&quot;">​</a></h3><p>При автосохранении и после импорта фоновый процесс расширения:</p><ol><li>Сохраняет <strong>объект настроек</strong> (опции, списки, таблицы Network/Props и т.д.) в <strong>IndexedDB</strong>, заведённый для профиля расширения — это основной, более устойчивый слой.</li><li><strong>Дублирует</strong> ту же структуру в <strong><code>chrome.storage.local</code></strong> под ключом вроде <strong><code>vue-inspector-settings</code></strong>, чтобы другие части расширения (в т.ч. совместимость со старыми путями и простой доступ) читали те же данные.</li></ol><p>В сам JSON настроек <strong>не встраиваются</strong> двоичные тела сохранённых файлов (фоны и др.): в объект уходят <strong>идентификаторы и метаданные</strong>, а сами байты лежат в <strong>отдельном хранилище IndexedDB</strong> (<code>vue-inspector-media</code> и связанные записи). Так уменьшается размер «шапки» настроек и ускоряется загрузка.</p><h3 id="автономныи-режим-standalone" tabindex="-1">Автономный режим (standalone) <a class="header-anchor" href="#автономныи-режим-standalone" aria-label="Permalink to &quot;Автономный режим (standalone)&quot;">​</a></h3><p>Настройки записываются через <strong>адаптер локального хранилища</strong> приложения в <strong>центральное хранилище</strong> (ключ вроде <strong><code>inspector-settings</code></strong> в KV-слое IndexedDB, доступ через встроенный <strong>storage iframe</strong>). Это <strong>не</strong> <code>chrome.storage</code> расширения: расширения в режиме закладки нет.</p><p>Медиафайлы для оформления и связанные блобы учитываются <strong>отдельно</strong> в том же контуре хранилища, с <strong>лимитом суммарного объёма</strong> (см. <a href="/docs/ru/options/customize.html">Персонализация</a>).</p><p>Дополнительно для ускорения после перезагрузки страницы может использоваться <strong>кэш в sessionStorage</strong> — он не заменяет постоянное хранилище, а лишь убирает «пустой первый кадр» интерфейса.</p><hr><h2 id="export-экспорт" tabindex="-1">Export (экспорт) <a class="header-anchor" href="#export-экспорт" aria-label="Permalink to &quot;Export (экспорт)&quot;">​</a></h2><p>По кнопке <strong>Export</strong> скачивается <strong>текстовый файл</strong> с именем вида <code>vue-inspector-settings-ГГГГ-ММ-ДД.txt</code>, внутри — <strong>форматированный JSON</strong> текущего состояния настроек из памяти приложения.</p><ul><li><strong>Standalone:</strong> для записей <strong>сохранённых файлов</strong> (<code>savedFiles</code>), у которых в хранилище есть блоб, экспорт при необходимости <strong>вкладывает содержимое в виде data URI</strong> в JSON — файл резервной копии получается более <strong>самодостаточным</strong> для переноса на другой браузер или ПК.</li><li><strong>Расширение:</strong> при формировании файла вложенные <strong>data URI</strong> для таких файлов <strong>убираются</strong> из JSON; в экспорт попадают в основном <strong>параметры и структура</strong>, а тяжёлые медиа по-прежнему живут <strong>только локально</strong> до тех пор, пока вы не перенесёте тот же профиль или не добавите файлы заново после импорта «сухого» набора.</li></ul><p>Экспорт удобен для <strong>резервной копии</strong>, <strong>переноса между машинами</strong> (особенно в standalone) и <strong>версионирования</strong> своих пресетов в системе контроля версий как обычного текстового файла.</p><hr><h2 id="import-импорт" tabindex="-1">Import (импорт) <a class="header-anchor" href="#import-импорт" aria-label="Permalink to &quot;Import (импорт)&quot;">​</a></h2><p><strong>Import</strong> открывает выбор файла; ожидается <strong>JSON</strong> того же вида, что и при экспорте (в интерфейсе фильтр обычно <strong><code>*.txt</code></strong>).</p><ol><li>Файл <strong>разбирается</strong> и <strong>сливается с заводским шаблоном</strong>: неизвестные поля отбрасываются или приводятся к актуальной схеме, устаревшие структуры <strong>мигрируют</strong> по возможности автоматически.</li><li>Результат попадает в <strong>ту же модель настроек</strong>, что используется при редактировании в Options, затем <strong>один раз записывается</strong> в постоянное хранилище вашего режима (расширение или standalone).</li><li>Интерфейс Options <strong>обновляет</strong> связанные списки (например breakpoints и mocks) из импортированных данных.</li></ol><p>При <strong>сохранении в постоянное хранилище</strong> тяжёлые вложения в JSON <strong>не дублируются</strong>: в текст настроек попадают в основном идентификаторы и параметры, а блобы остаются в <strong>медиа-слое</strong>. Импорт <strong>полного</strong> файла из <strong>standalone</strong>-экспорта (где в JSON вшиты data URI) поднимает эти записи в рабочее состояние; импорт «облегчённого» файла из <strong>расширения</strong> переносит прежде всего опции и списки — сами картинки/видео для фона на новом месте может понадобиться <strong>выбрать заново</strong> в Customize.</p><p>При ошибке формата импорт <strong>не применяется</strong>; текст ошибки показывается в форме.</p><p>Импорт <strong>перезаписывает текущее состояние</strong> согласно файлу (в разрезе ключей, которые удалось корректно разобрать). Перед проверкой чужого пресета сделайте <strong>Export</strong> текущего профиля, чтобы можно было вернуться назад.</p><hr><h2 id="reset-сброс" tabindex="-1">Reset (сброс) <a class="header-anchor" href="#reset-сброс" aria-label="Permalink to &quot;Reset (сброс)&quot;">​</a></h2><p><strong>Reset</strong> возвращает настройки к <strong>заводским значениям</strong> и очищает связанные <strong>медиа-хранилища</strong> (блобы фонов и сохранённых файлов). Для расширения дополнительно вызывается сценарий полного сброса в фоне (очистка IndexedDB настроек и ключей <code>vue-inspector-settings</code> в <code>chrome.storage.local</code>). В standalone сброс записывается в локальное хранилище приложения тем же каналом, что и обычное сохранение.</p><p>Операция <strong>необратима</strong> без заранее сохранённого файла экспорта.</p><p>Тонкий сброс только Auto Run без полного Reset доступен через <strong>всплывающее окно</strong> расширения (см. <a href="/docs/ru/options/auto_run.html">Автозапуск</a>); кнопка <strong>Reset</strong> в Options затрагивает <strong>весь</strong> профиль целиком.</p><hr><h2 id="см-также" tabindex="-1">См. также <a class="header-anchor" href="#см-также" aria-label="Permalink to &quot;См. также&quot;">​</a></h2><ul><li><a href="/docs/ru/guide/install.html#storage">Установка — хранение</a></li><li><a href="/docs/ru/options/customize.html">Персонализация</a></li><li><a href="/docs/ru/options/auto_run.html">Автозапуск</a></li></ul>',34)])])}const m=o(e,[["render",a]]);export{h as __pageData,m as default};
